// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// STRY0074595
	var s_office_abbreviation = current.office_abbreviation + '';
	if(current.u_external_flag==true){
		if(!s_office_abbreviation.startsWith("EXT - ")){
			current.office_abbreviation = 'EXT - ' + s_office_abbreviation;
		}
	}else{
		if(s_office_abbreviation.startsWith("EXT - ")){
			var strlength = s_office_abbreviation.length;
			if(strlength > 6){
				current.office_abbreviation = s_office_abbreviation.substring(6, strlength); // 6 b/c it is zero base array
			}else{
				current.office_abbreviation = '';
			}
		}
	}
})(current, previous);
